{
  "name": "Health First Colorado Buy-In (QMB, SLMB, QI)",
  "eligibility": {
    "age": 65,
    "income_limits": "These are federal Medicare Savings Programs (MSPs) administered through Health First Colorado. Exact 2026 income limits not specified in sources; limits vary by tier (QMB, SLMB, QI) and are typically 100% FPL for QMB, 120% for SLMB, 135% for QI, adjusted annually for household size. Contact county office for current dollar amounts as they differ for single/couple (e.g., QMB often up to ~$1,255/month single, ~$1,695 couple, but verify).[1][3]",
    "asset_limits": "There are three levels of MSP depending on income and asset limits. Specific 2026 asset limits (typically $9,660 individual/$14,490 couple, excluding home, car, etc.) not detailed; what counts includes bank accounts, stocks; exempts primary home, one vehicle, personal items. Confirm with local office.[1]",
    "other_requirements": ["Must be enrolled in Medicare Part A.", "Colorado resident.", "U.S. citizen or qualified immigrant.", "For elderly loved ones: age 65+ or disabled under 65 on Medicare."]
  },
  "benefits": {
    "type": "financial",
    "value": "**QMB:** Pays Medicare Part B monthly premium, deductibles, copays, coinsurance (covers the 20% Medicare does not, providing full coverage). **SLMB & QI-1:** Pays Part B monthly premium only; responsible for deductibles, copays, coinsurance (supplemental plans may fill gaps).[1]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.healthfirstcolorado.com/apply-now/ [4]", "Phone: Contact local county human services office (find via https://cdhs.colorado.gov/counties or 1-800-221-3943).", "Mail or in-person: Local county Department of Human Services office.[1][4]"],
    "processing_time": "Not specified in sources; typically 45 days for Medicaid programs.",
    "waitlist": "QI often has federal funding caps and waitlists; others generally no waitlist.[1]",
    "forms": ["Health First Colorado application (online or paper via county); no specific MSP form named.[4]"],
    "documents": ["Proof of income (pay stubs, tax returns), assets (bank statements), Medicare card, ID (birth certificate, Social Security card), proof of residency, disability if applicable.[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available through all Colorado counties.",
    "regional_variations": "Administered by county human services offices; processing times may vary by county, but no specific differences noted.[1][4]",
    "offices_or_providers": ["Local county Department of Human Services offices statewide."]
  },
  "official_source": "https://hcpf.colorado.gov/medicaid-buy-program (related buy-in); for MSPs: https://www.healthfirstcolorado.com/ [1][2][4]",
  "gotchas": ["Must already have Medicare enrollment; QMB provides fuller coverage than SLMB/QI (people miss that SLMB/QI leave you paying deductibles/copays).[1]", "Asset test applies (unlike standard Medicaid in some cases); QI has limited slots.[1][3]", "Not the disability 'Buy-In for Working Adults'—that's separate with premiums based on income.[2]", "Work requirements starting 2027 exempt buy-in/disability programs but confirm MSP status.[5][6]"],
  "data_shape_notes": "Tiered by QMB/SLMB/QI with differing income/asset limits and benefit levels; financial assistance tied to Medicare premiums/coinsurance; asset exclusions standard but tested; funding caps for QI."
}

{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to anyone eligible for Medicare (typically age 65+ or under 65 with disabilities), family members, and caregivers. Supports people with limited incomes but not restricted by specific dollar amounts[1][2][4].",
    "asset_limits": "No asset limits or tests apply[1][2].",
    "other_requirements": ["Must be eligible for Medicare or soon to be eligible", "Family members and caregivers of Medicare beneficiaries can access services", "No requirement to be enrolled yet; contact 3 months before Medicare starts recommended[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized counseling and assistance on Medicare options (Parts A, B, C, D, Medigap), enrollment, appeals, prescription drug costs, coordinating benefits, applying for low-income programs (Medicaid, Medicare Savings Program, Extra Help), managing bills; public education, outreach presentations, enrollment events; unbiased advice (counselors not licensed to sell insurance); some programs offer study guides, legal referrals[1][2][3][4][6].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-888-696-7213 (8:30 am - 4:30 pm), Spanish: 303-894-5953[3][5]", "Website: https://doi.colorado.gov/insurance-products/health-insurance/senior-health-care[3][5]", "Email: Brandon.D.Davis@state.co.us[3]", "In-person: Through local partners like area agencies on aging (e.g., Denver Regional Council of Governments for Arapahoe, Douglas, Jefferson counties)[3][8]"],
    "processing_time": "No formal application or processing; services provided immediately via phone or in-person counseling[1][4].",
    "waitlist": null,
    "forms": ["No specific forms required for counseling; may assist with Medicare enrollment or low-income program applications during sessions[2]"],
    "documents": ["Medicare card, current insurance details, prescription drug list, medical bills/statements (recommended for personalized help, but not mandatory to start)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide[3][5]",
    "regional_variations": "Delivered through state Department of Regulatory Agencies in partnership with local area agencies on aging and community partners (e.g., DRCOG serves Arapahoe, Douglas, Jefferson counties); no differences in services, eligibility, or wait times noted[3][6][8]",
    "offices_or_providers": ["State office: Department of Regulatory Agencies, 1560 Broadway, Suite 850, Denver, CO 80202[3]", "Local: Area Agencies on Aging and over 2,200 national sites, including Colorado partners[2][6][8]"]
  },
  "official_source": "https://doi.colorado.gov/insurance-products/health-insurance/senior-health-care",
  "gotchas": ["Not insurance agents; cannot sell plans or recommend specific products—only provide unbiased information[1]", "Intensive training (8-10 hours) ensures expertise, but services are counseling only, not direct financial aid or healthcare[1][2]", "Often confused with Medicare itself; it's free help navigating Medicare, not a health plan[4]", "Contact early (3 months before Medicare starts) to avoid enrollment penalties[1]", "May refer to Senior Medicare Patrol (SMP) for fraud issues, which some SHIPs provide alongside[2][8]"],
  "data_shape_notes": "no income or asset test; eligibility tied solely to Medicare status; statewide with local delivery partners; service-based (counseling hours unlimited, no caps); unbiased non-sales focus unique to SHIP vs. private advisors"
}

{
  "name": "Meals on Wheels Colorado",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits statewide; sliding scale fees or voluntary contributions based on income in some areas (e.g., Fort Collins verifies gross monthly income for reduced fees; Broomfield any income level; Loveland suggested contributions for 60+ with no denial for inability to pay)[1][2][3][5]",
    "asset_limits": "No asset limits mentioned across providers",
    "other_requirements": ["Primarily homebound and unable to shop for or prepare meals due to age, disability, illness, or recent hospitalization", "Live in service area (varies by provider)", "Safe and accessible home for delivery in some areas (e.g., Fort Collins)", "Dietary needs met by provider", "Under 60 may qualify with disability documentation or medical referral"][1][2][3][5][7]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals (e.g., full lunch with hot entrée, vegetable, starch, roll, salad, dessert meeting 1/3 to 1/2 daily requirements; frozen weekend meals in some areas); delivered weekdays 11am-12:30pm; costs $3.50-$7.50 per meal or voluntary contribution, no one denied for inability to pay",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone (varies: Fort Collins 970-484-6325; Larimer 970-472-9630; Adams/Arapahoe/Denver/Douglas/Jefferson/Gilpin/Clear Creek 303-294-0111; Lafayette/Louisville/Erie/Superior 303-665-0566); Online forms (e.g., mealsonwheelsfc.org client application, coalcreekmow.org); Mail application (e.g., Mesa County); In-person assessment possible via provider contact"][1][7][8],
    "processing_time": "Varies; office call after application receipt to schedule start; longer wait times due to application influx in some areas like Mesa County",
    "waitlist": "Possible in high-demand areas (e.g., Mesa County notes longer wait times)",
    "forms": ["Client application (Fort Collins); Congregate Intake Form (Mesa County dining); general intake/assessment by provider"],
    "documents": ["Proof of age/disability if under 60; gross monthly income verification for sliding scale (some areas); doctor referral for under 60 or short-term"][1][2][3][4]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to specific counties/cities served by local providers (e.g., Fort Collins/Laporte/Wellington; Loveland/Berthoud/southern Larimer; Broomfield; Mesa County; Adams/Arapahoe/Denver/Douglas/Jefferson/Gilpin/Clear Creek; Lafayette/Louisville/Erie/Superior)",
    "regional_variations": "Eligibility details, costs, age cutoffs (60+ or 62+), delivery areas, fees (fixed sliding scale vs. voluntary), and providers differ; e.g., Fort Collins nonprofit fees $6.50-$7.50; Loveland voluntary for 60+; Mesa donation-based $3.50 suggested",
    "offices_or_providers": ["Meals on Wheels Fort Collins (mealsonwheelsfc.org); Meals on Wheels Loveland & Berthoud (lovelandmealsonwheels.org); Broomfield Meals on Wheels (broomfield.org); Meals on Wheels Mesa County (mealsonwheelsmesacounty.org); VOA Colorado (various counties); Coal Creek Meals on Wheels (coalcreekmow.org)"][1][3][5][7][8]
  },
  "official_source": "No single statewide .gov site; local providers via mealsonwheelsamerica.org/find-meals-and-services or county sites like broomfield.org[4][5]",
  "gotchas": ["Not a single statewide program—must contact local provider for exact area coverage and rules; boundaries due to food safety/volunteer access; fees apply in some areas despite subsidies (sliding scale, not free); waitlists in high demand; under 60 needs disability proof; confirm service area as not all Colorado covered"],
  "data_shape_notes": "Decentralized local providers with varying eligibility (age 60-62+, homebound focus), no uniform income/assets test, region-specific fees/voluntary contributions, county-restricted coverage"
}

{
  "name": "Colorado Legal Services (Legal Aid for Seniors)",
  "eligibility": {
    "age": 60,
    "income_limits": "For seniors (60+), no income limits in certain programs like Senior Law Project (e.g., Larimer County); generally, low-income based on 125% of 2024 Federal Poverty Guidelines for others, but exact dollar amounts/tables not specified in sources—must contact for current FPG table by household size[1][2][8].",
    "asset_limits": "No asset limits for seniors (60+) in senior-specific programs[2].",
    "other_requirements": ["Low-income priority or 60+ age waiver[1]", "Colorado resident[1]", "Civil legal issues only (not criminal, traffic, etc.)[1][2]", "Case-by-case for immigration categories if applicable[2]", "High social/economic need prioritized under Older Americans Act[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal services including attorney advice, assistance filing cases, full court representation; covers housing/evictions, public benefits (Social Security, Medicare, Medicaid, SSI), advance directives (living wills, powers of attorney), economic justice (debt, etc.), elder abuse/neglect prevention; social worker support in some areas (Denver, Colorado Springs)[1][2][3][4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online pre-apply: https://www.coloradolegalservices.org/get-help/[6]", "Phone: Call central intake (number via website or local office)[1][6]", "In-person: 13 offices statewide—find via https://www.coloradolegalservices.org/get-help/[3][6]", "Mail/intake process required for all[1][6]"],
    "processing_time": "Team contacts after application; intake required, but no specific timeline stated[1][6].",
    "waitlist": "Limited resources mean unable to serve all (e.g., 323 elders turned away in 2021); some cases opened monthly (900+ in Aug)[1][4].",
    "forms": ["Intake process (no specific form name/number listed; pre-apply online)[1][6]"],
    "documents": ["Not explicitly listed; prepare ID, proof of income/residency if needed, details of legal issue; multilingual intake support available[1][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all Colorado; some offices county-specific (e.g., Metro: Adams, Arapahoe, Broomfield, Clear Creek, Denver, Douglas, Elbert; Larimer County senior project)[2][3][7].",
    "regional_variations": "13 offices with varying case types accepted due to resources; different AAAs contract local providers for elders; wait times/resources vary (e.g., housing priority statewide)[3][4].",
    "offices_or_providers": ["13 CLS offices; 21 legal assistance providers via 16 AAA regions for elders[3][4]"]
  },
  "official_source": "https://www.coloradolegalservices.org",
  "gotchas": ["Not a hotline—intake screening required first[2]", "Can't take every case due to resources; turn away eligible applicants[1][4][5]", "Some offices limit case types[2]", "Seniors may bypass income test but still prioritized by need[1][2][4]", "Separate from state-funded elder program via Disability Law Colorado/AAAs[4]"],
  "data_shape_notes": "Seniors 60+ often no income/asset test but prioritized by need via AAAs/private providers; 13 CLS offices + regional variations; resource-limited with case prioritization"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available regardless of financial status.",
    "asset_limits": "No asset limits or tests; no financial eligibility requirements.",
    "other_requirements": ["Must be a resident of a skilled nursing home or licensed assisted living residence in Colorado (or a relative, friend, facility staff, or concerned individual on their behalf). No age requirement specified, though often relevant for elderly residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including receiving and resolving complaints on quality of care, use of restraints, transfers/discharges, abuse, privacy/dignity issues, medications, hygiene, staff attitudes, and resident rights violations. Services are confidential, resident-directed, and free. Ombudsmen visit facilities regularly (e.g., nursing homes weekly, assisted living bi-monthly in some areas).",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Online: https://www.coombudsman.org (use 'Find an Ombudsman' to locate local office)", "Phone: State level 720-925-8609 (Jesse Bond for info); local examples - Boulder 303-441-1170, Pueblo 719-601-6282", "Email: jesse.bond@state.co.us (state coordinator); local examples - ecorson@bouldercounty.gov (Boulder), dmason@srda.org (Pueblo)", "In-person: Local long-term care facilities or regional offices (network across state)"],
    "processing_time": "Immediate assistance for complaints; no formal processing time as it's not an enrollment-based benefit program.",
    "waitlist": null,
    "forms": ["No specific application forms for receiving services; contact local ombudsman directly to file a complaint or request help. Volunteer applications exist separately but not for residents."],
    "documents": ["No documents required; provide details of the complaint or concern verbally or via phone/email."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of licensed skilled nursing homes and assisted living facilities in Colorado.",
    "regional_variations": "Managed by a network of local offices with different providers (e.g., Boulder County Community Services, Pueblo SRDA). Visit frequency may vary (e.g., Boulder: nursing homes weekly, assisted living twice monthly). Different contact points and staff per region.",
    "offices_or_providers": ["State: https://www.coombudsman.org", "Boulder: Erica Corson, 303-441-1170", "Pueblo: SRDA, 719-601-6282"]
  },
  "official_source": "https://www.coombudsman.org",
  "gotchas": ["Not a healthcare or financial aid program—purely advocacy for rights and complaint resolution, not direct care or funding.", "Services are resident-directed and confidential; family cannot override resident's wishes.", "Only covers licensed skilled nursing homes and assisted living—not home care, adult day care, or unlicensed facilities.", "Anyone can contact (residents, families, staff, public), but intervention requires resident direction.", "Volunteering requires separate 36-hour training and commitment, often confused with receiving services."],
  "data_shape_notes": "no income/asset test; advocacy-only with statewide network of local offices; facility-residency required; free/confidential/resident-directed; regional providers handle delivery with visit frequency variations"
}

